    # ── Actions ───────────────────────────────────────────────────────────────

    def enter_username(self, username):
        """Enter username in the username/email field"""
        # Try email input first, fallback to username input
        if self.is_element_visible(EMAIL_INPUT, timeout=2000):
            self.wait_and_fill(EMAIL_INPUT, username)
        else:
            self.wait_and_fill(USERNAME_INPUT, username)

    def enter_password(self, password):
        """Enter password in the password field"""
        self.wait_and_fill(PASSWORD_INPUT, password)

    def click_login_button(self):
        """Click the login/submit button"""
        if self.is_element_visible(LOGIN_BUTTON, timeout=2000):
            self.wait_and_click(LOGIN_BUTTON)
        else:
            self.wait_and_click(SUBMIT_BUTTON)
        self.wait_for_page_load()

    def submit_login(self, username, password):
        """Complete login flow with username and password"""
        self.enter_username(username)
        self.enter_password(password)
        self.click_login_button()

